Class-Based (Recommended)Functional agents/search_bot/agent.py<pre><code>from __future__ import annotations

from dataclasses import dataclass, field

from agentomatic.agents import BaseGraphAgent
from agentomatic.agents.graph import GraphBuilder


@dataclass
class SearchState:
    query: str = ""
    documents: list[str] = field(default_factory=list)
    answer: str = ""


class SearchBot(BaseGraphAgent[SearchState]):
    name = "Search Bot"
    description = "Knowledge-base search with citations."

    def build_graph(self, builder: GraphBuilder) -&gt; None:
        builder.add_node("retrieve", self.retrieve_docs)
        builder.add_node("generate", self.generate_response)
        builder.add_edge("retrieve", "generate")
        builder.set_entry_point("retrieve")
        builder.set_finish_point("generate")

    def retrieve_docs(self, state: SearchState) -&gt; dict:
        state.documents = ["doc1", "doc2"]
        return {"documents": state.documents}

    def generate_response(self, state: SearchState) -&gt; dict:
        state.answer = f"Based on {len(state.documents)} docs..."
        return {"answer": state.answer}

    def input_to_state(self, payload: dict) -&gt; SearchState:
        return SearchState(query=payload.get("query", ""))

    def state_to_output(self, state: SearchState) -&gt; dict:
        return {"answer": state.answer}
</code></pre> <p>Why class-based?</p> <ul> <li>Typed state — catch bugs at development time</li> <li>ML lifecycle — <code>compile() → fit() → evaluate() → transform()</code></li> <li>Self-contained — one file, one class, one import</li> <li>Graph viz — Studio renders your <code>build_graph()</code> topology</li> </ul> agents/search_bot/__init__.py<pre><code>from __future__ import annotations

from agentomatic.core.manifest import AgentManifest

manifest = AgentManifest(
    name="Search Bot",
    slug="search_bot",
    description="Knowledge-base search with citations.",
    framework="langgraph",
    version="1.0.0",
)


def retrieve_docs(state: dict) -&gt; dict:
    """Node: fetch relevant documents."""
    state["documents"] = ["doc1", "doc2"]
    return state


def generate_response(state: dict) -&gt; dict:
    """Node: produce an answer from documents."""
    state["answer"] = f"Based on {len(state['documents'])} docs..."
    return state


def graph_fn():
    """Build and return the LangGraph StateGraph."""
    from langgraph.graph import StateGraph

    g = StateGraph(dict)
    g.add_node("retrieve", retrieve_docs)
    g.add_node("generate", generate_response)
    g.add_edge("retrieve", "generate")
    g.set_entry_point("retrieve")
    g.set_finish_point("generate")
    return g.compile()
</code></pre> <p>When to use functional</p> <ul> <li>Quick prototypes or single-node agents</li> <li>Gradual migration from raw LangGraph code</li> <li>Scripts that don't need typed state or ML lifecycle</li> </ul>

build_graph() API (Recommended)Decorator API (Legacy) <p>The <code>build_graph()</code> API gives you explicit control over the graph topology using agentomatic's built-in <code>GraphBuilder</code>. Define nodes as plain methods and wire them in <code>build_graph()</code>.</p> <pre><code>from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any

from agentomatic.agents import BaseGraphAgent


@dataclass
class SummaryState:
    """Per-run transient state."""

    query: str = ""
    chunks: list[str] = field(default_factory=list)
    summary: str = ""


class SummaryAgent(BaseGraphAgent[SummaryState]):
    """Summarises documents into concise briefs."""

    agent_name = "summarizer"
    agent_description = "Document summarisation agent"

    def __init__(self, *, llm: Any = None) -&gt; None:
        super().__init__()
        self.llm = llm
        self.system_prompt = "You are a summarisation expert."

    # --- graph wiring ---

    def build_graph(self):
        g = self.new_graph()
        g.add_node("extract", self.extract)
        g.add_node("summarise", self.summarise)
        g.add_node("format_output", self.format_output)
        g.set_entry_point("extract")
        g.add_edge("extract", "summarise")
        g.add_edge("summarise", "format_output")
        g.set_finish_point("format_output")
        return g.compile()

    # --- node methods (plain methods, no decorators) ---

    def extract(self, state: SummaryState) -&gt; SummaryState:
        """Split input into chunks."""
        state.chunks = [state.query[i : i + 200]
                        for i in range(0, len(state.query), 200)]
        return state

    def summarise(self, state: SummaryState) -&gt; SummaryState:
        """Summarise each chunk (placeholder)."""
        state.summary = " ".join(
            f"[{c[:30]}...]" for c in state.chunks
        )
        return state

    def format_output(self, state: SummaryState) -&gt; SummaryState:
        """Prepare the final response."""
        return state

    # --- state conversion ---

    def input_to_state(
        self, input_data: dict[str, Any],
    ) -&gt; SummaryState:
        return SummaryState(
            query=input_data.get("query", ""),
        )

    def state_to_output(
        self, state: SummaryState,
    ) -&gt; dict[str, Any]:
        return {
            "summary": state.summary,
            "num_chunks": len(state.chunks),
        }


# Usage
agent = SummaryAgent(llm="openai/gpt-4o")
result = agent.transform({"query": "Long document text..."})
print(result)
# {"summary": "[Long document t...]", "num_chunks": 1}
</code></pre> <p>For simple linear chains, you can use <code>@agent_node</code> decorators as a shorthand. The framework auto-builds the graph from decorator metadata.</p> <pre><code>from __future__ import annotations

from dataclasses import dataclass
from typing import Any

from agentomatic.agents import BaseGraphAgent, agent_node


@dataclass
class QAState:
    question: str = ""
    answer: str = ""


class QAAgent(BaseGraphAgent[QAState]):
    agent_name = "qa_bot"

    def __init__(self, *, llm: Any = None) -&gt; None:
        super().__init__()
        self.llm = llm

    @agent_node(entrypoint=True)
    def retrieve(self, state: QAState) -&gt; QAState:
        state.answer = f"Answer for: {state.question}"
        return state

    @agent_node(after="retrieve", finish=True)
    def generate(self, state: QAState) -&gt; QAState:
        return state

    def input_to_state(self, data: dict[str, Any]) -&gt; QAState:
        return QAState(question=data.get("query", ""))

    def state_to_output(self, state: QAState) -&gt; dict[str, Any]:
        return {"answer": state.answer}
</code></pre> <p>Which API should I choose?</p> <p>Use <code>build_graph()</code> for all new agents — it's explicit, flexible, and familiar to LangGraph users. The decorator API is still supported as a convenience for simple linear chains, but <code>build_graph()</code> is recommended.</p>

Node method doesn't return state <p>Every node method must return the updated state object. If you forget <code>return state</code>, the graph will pass <code>None</code> to the next node.</p> <pre><code># ❌ Wrong — missing return
def process(self, state: MyState) -&gt; MyState:
    state.output = {"response": "Hello"}

# ✅ Correct
def process(self, state: MyState) -&gt; MyState:
    state.output = {"response": "Hello"}
    return state
</code></pre> Forgot to call <code>super().__init__()</code> <p>If you override <code>__init__</code>, you must call <code>super().__init__()</code> first:</p> <pre><code>def __init__(self, *, llm=None):
    super().__init__()  # ← Don't forget this!
    self.llm = llm
</code></pre> Graph not rebuilding after code changes <p>The graph is cached after the first <code>build_graph()</code> call. If you change your graph topology, call <code>self.invalidate_graph()</code> to force a rebuild.</p> Can I use async node methods? <p>Yes! Both sync and async node methods work. The graph runtime handles both:</p> <pre><code>async def process(self, state: MyState) -&gt; MyState:
    result = await some_async_llm_call(state.query)
    state.output = {"response": result}
    return state
</code></pre> How do I use class agents with <code>prompts.json</code>? <p>Class agents work with all optional overrides. Place a <code>prompts.json</code> in your agent's folder and use <code>PromptManager</code> in your node methods:</p> <pre><code>from agentomatic import PromptManager

class MyAgent(BaseGraphAgent[MyState]):
    def __init__(self):
        super().__init__()
        self.prompts = PromptManager.from_file(
            "agents/my_agent/prompts.json"
        )

    def generate(self, state):
        prompt = self.prompts.format(
            "v1", "user_template", query=state.query
        )
        # Use prompt with your LLM...
</code></pre> How do I add custom schemas to a class agent? <p>Create a <code>schemas.py</code> file in your agent's folder. Agentomatic discovers it automatically:</p> <pre><code># agents/my_agent/schemas.py
from pydantic import BaseModel, Field

class CustomInvokeRequest(BaseModel):
    query: str = Field(..., description="User question")
    language: str = Field("en", description="Response language")
    max_length: int = Field(500, description="Max response length")
</code></pre> <p>The auto-generated <code>/invoke</code> endpoint will now use your custom schema for both validation and Swagger docs.</p> What's the difference between <code>transform()</code> and <code>invoke()</code>? <p>They are identical — <code>invoke()</code> is simply an alias for <code>transform()</code>. Both execute the full pipeline: <code>input_to_state() → graph execution → state_to_output()</code>.</p> <code>current_query</code> vs <code>query</code> — which key should I use in <code>input_to_state</code>? <p>The REST API sends <code>query</code> in the <code>AgentInvokeRequest</code> body. The router maps this to <code>current_query</code> in the state dict before invoking your agent. In class agents, you control <code>input_to_state()</code> directly, so use whatever key your API sends:</p> <pre><code>def input_to_state(self, input_data):
    # input_data comes directly from the REST request body
    return MyState(query=input_data.get("query", ""))
</code></pre>

